package com.github.andreyasadchy.xtra.repository

internal object KickInlineBadgeData {
    private val baseByType: Map<String, String> = mapOf(
        "bot" to "data:image/svg+xml;base64,",
        "broadcaster" to "data:image/svg+xml;base64,",
        "founder" to "data:image/svg+xml;base64,",
        "moderator" to "data:image/svg+xml;base64,",
        "og" to "data:image/svg+xml;base64,",
        "sidekick" to "data:image/svg+xml;base64,",
        "staff" to "data:image/svg+xml;base64,",
        "subscriber" to "data:image/svg+xml;base64,",
        "verified" to "data:image/svg+xml;base64,",
        "vip" to "data:image/svg+xml;base64,",
    )

    val byType: Map<String, String> = baseByType

    fun forBadge(type: String, version: String? = null): String? {
        return if (type == "sub_gifter") {
            KickInlineGiftSubBadgeData.forQuantity(version?.toIntOrNull() ?: 1)
        } else {
            baseByType[type]
        }
    }
}
